import React, { useState } from 'react';
import { ngoApi } from '../../../services/api';

export default function CreateFunds() {
  const [form, setForm] = useState({
    userCert: '',
    fundId: '',
    ngoId: '',
    title: '',
    purpose: '',
    fundTarget: '',
  });
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState(null);

  const onChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const onSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage(null);
    try {
      const res = await ngoApi.createFund(form);
      setMessage(res?.data || 'Fund created successfully');
    } catch (err) {
      setMessage(err?.response?.data?.error || err.message || 'Failed to create fund');
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={onSubmit} style={{ maxWidth: 800, margin: '0 auto' }}>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
        <div>
          <label>User Cert</label>
          <input
            name="userCert"
            value={form.userCert}
            onChange={onChange}
            placeholder="userCert"
            required
          />
        </div>

        <div>
          <label>Fund ID</label>
          <input
            name="fundId"
            value={form.fundId}
            onChange={onChange}
            placeholder="fundId"
            required
          />
        </div>

        <div>
          <label>NGO ID</label>
          <input
            name="ngoId"
            value={form.ngoId}
            onChange={onChange}
            placeholder="ngoId"
            required
          />
        </div>

        <div>
          <label>Title</label>
          <input
            name="title"
            value={form.title}
            onChange={onChange}
            placeholder="title"
            required
          />
        </div>

        <div>
          <label>Purpose</label>
          <input
            name="purpose"
            value={form.purpose}
            onChange={onChange}
            placeholder="purpose"
            required
          />
        </div>

        <div>
          <label>Fund Target</label>
          <input
            name="fundTarget"
            value={form.fundTarget}
            onChange={onChange}
            placeholder="fundTarget"
            type="number"
            required
          />
        </div>
      </div>

      <button type="submit" disabled={loading} style={{ marginTop: '12px', width: '100%' }}>
        {loading ? 'Sending...' : 'Send Request'}
      </button>

      {message && <div style={{ marginTop: 12 }}>{String(message)}</div>}
    </form>
  );
}
